// import { messaging } from 'firebase'
// import firestore from 'redux-firestore'
import { firebase } from 'firebase/app'
import { get } from 'lodash'
import messageActions from '../notification'
import { publicVapidKey } from '../../config/Firebase'

/**
 * Write FCM messagingToken to user profile
 * @param {String} messagingToken - Token to be written to user profile
 */

function updateUserProfileWithToken (messagingToken) {
  const currentUserUid =
    firebase.auth().currentUser && firebase.auth().currentUser.uid

  if (!currentUserUid) {
    return
  }

  return firebase.firestore()
    .collection('users')
    .doc(currentUserUid)
    .update({
      messaging: {
        mostRecentToken: messagingToken,
        updatedAt: firebase.firestore.FieldValue.serverTimestamp()
      }
    })
}

/**
 * Get messaging token from Firebase messaging
 */
function getMessagingToken () {
  return firebase.messaging()
    .getToken()
    .catch(err => {
      console.error('Unable to retrieve refreshed token ', err) // eslint-disable-line no-console
      return Promise.reject(err)
    })
}

/**
 * Get Cloud Messaging Token and write it to the currently logged
 * in user's profile
 */
function getTokenAndWriteToProfile () {
  return getMessagingToken().then(updateUserProfileWithToken)
}

/**
 * Request permission from the user to display display
 * browser notifications
 */
export function requestPermission () {
  return firebase.messaging()
    .requestPermission()
    .then(getTokenAndWriteToProfile)
    .catch(err => {
      console.error('Unable to get permission to notify: ', err) // eslint-disable-line no-console

      return Promise.reject(err)
    })
}

/**
 * Setup Firebase Cloud Messaging. This  requests permission from the
 * user to show browser notifications. If the user approves or if they have
 * approved in the passed, then a Cloud Messaging Token is written to the
 * user's profile.
 * @param {Function} dispatch - redux action dispatching function
 */
export function initializeMessaging (dispatch) {
  const messaging = firebase.messaging()

  if (!publicVapidKey) {
    /* eslint-disable no-console */
    console.warn(
      'Skipping messaging initialization, publicVapidKey not set in src/config.js'
    )
    /* eslint-enable no-console */
    return
  }

  messaging.usePublicVapidKey(publicVapidKey)

  // Handle Instance ID token updates
  messaging.onTokenRefresh(() => {
    getTokenAndWriteToProfile()
  })

  /*
   * Handle incoming messages. Called when:
   * - a message is received while the app has focus
   * - the user clicks on an app notification created by a service worker
   *   `messaging.setBackgroundMessageHandler` handler.
   */
  messaging.onMessage(payload => {
    const DEFAULT_MESSAGE = 'Message!'
    // Dispatch showSuccess action

    messageActions.showSuccess(
      get(payload, 'notification.body', DEFAULT_MESSAGE)
    )(dispatch)
  })

  // Request permission to setup browser notifications
  requestPermission()
}

import {
  NOTIFICATION_SHOW,
  NOTIFICATION_DISMISS,
  NOTIFICATION_CLEAR
} from './actionTypes'

const defaultDismissTime = 2500 // 2.5 seconds

/**
 * Publish a notification. if `dismissAfter` is set, the notification will be
 * auto dismissed after the given period.
 * @param {Object} notif - Object containing
 * @param {Object} notif.kind - Kinda of notification (success, warning, failure)
 * @param {Object} notif.message - Notification message
 * @param {Object} notif.dismissAfter - Time after which to dismiss notification (default time set in constants)
 */
export function showNotification (notif) {
  const payload = Object.assign({}, notif)
  // Set default id to now if none provided
  if (!payload.id) {
    payload.id = Date.now()
  }
  return dispatch => {
    dispatch({ type: NOTIFICATION_SHOW, payload })

    setTimeout(() => {
      dispatch({
        type: NOTIFICATION_DISMISS,
        payload: payload.id
      })
    }, payload.dismissAfter || defaultDismissTime)
  }
}

/**
 * Show message for a success
 * @param {String} message - Message to show
 */
export function showSuccess (message) {
  return showNotification({ type: 'success', message })
}

/**
 * Show message for a error
 * @param {String} message - Message to show
 */
export function showError (message) {
  return showNotification({ type: 'error', message: `Error: ${message || ''}` })
}

/**
 * Dismiss a notification by the given id.
 * @param {Number} id - notification id
 */
export function dismissNotification (payload) {
  return {
    type: NOTIFICATION_DISMISS,
    payload
  }
}

/**
 * Clear all notifications
 */
export function clearNotifications () {
  return { type: NOTIFICATION_CLEAR }
}

import { compose, withHandlers } from 'recompose'
import { withStore } from '../../../utils/components'
import * as actions from '../actions'

const withNotifications = compose(
  withStore,
  withHandlers({
    showError: ({ store }) => err => actions.showError(err)(store.dispatch),
    showSuccess: ({ store }) => err => actions.showSuccess(err)(store.dispatch),
    dismissNotification: ({ store }) => id =>
      actions.dismissNotification(id)(store.dispatch)
  })
)

export default withNotifications

import { env as environment, Firebase as firebase, sentryDsn } from '../../config/Firebase'
import { version } from '../../../package.json'

let errorHandler

/**
 * Initialize Stackdriver Error Reporter only if api key exists
 */
function initStackdriverErrorReporter () {
  if (typeof window.StackdriverErrorReporter === 'function') {
    window.addEventListener('DOMContentLoaded', () => {
      const errorHandler = new window.StackdriverErrorReporter()

      errorHandler.start({
        key: firebase.apiKey,
        projectId: firebase.projectId,
        service: 'AINA',
        version
      })
    })
  }

  return errorHandler
}

/**
 * Initialize Raven (reports to sentry.io)
 */
function initRaven () {
  if (sentryDsn && window.Raven) {
    window.Raven.config(sentryDsn, {
      environment,
      release: version
    }).install()
  }
}

/**
 * Initialize client side error reporting. Error handling is only
 * initialized if in production environment.
 */
export function init () {
  if (environment === 'production') {
    initStackdriverErrorReporter()
    initRaven()
  } else {
    errorHandler = console.error // eslint-disable-line no-console
  }

  return errorHandler
}

/**
 * Set user's uid within error reporting context (can be one or
 * many error handling utilities)
 * @param {Object} auth - Authentication data
 * @param {String} auth.uid - User's id
 */
export function setErrorUser (auth) {
  if (auth && auth.uid && environment === 'production') {
    // Set user within Stackdriver
    if (errorHandler && errorHandler.setUser) {
      errorHandler.setUser(auth.uid)
    }
    // Set user within Raven (so it will show in Sentry)
    if (window.Raven && window.Raven.setUserContext) {
      window.Raven.setUserContext({
        id: auth.uid,
        email: auth.email || 'none'
      })
    }
  }
}

export default errorHandler

